//| Enter a market order given the trade type (OP_BUY/OP_SELL)       |
//+------------------------------------------------------------------+
void EnterMarketOrder(int tradeType) {
   double openPrice = (tradeType == OP_BUY) ? Ask : Bid;
   double sl = (tradeType == OP_BUY) ? openPrice - StopLossPips * Point : openPrice + StopLossPips * Point;
   double tp = (tradeType == OP_BUY) ? openPrice + TakeProfitPips * Point : openPrice - TakeProfitPips * Point;

   int ticket = OrderSend(Symbol(), tradeType, Lots, openPrice, 3, sl, tp, NULL, 0, 0, clrNONE);
   if (ticket <= 0) {
      Print("Error opening ", (tradeType == OP_BUY) ? "Buy" : "Sell", " order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Manage the existing open order                                   |
//+------------------------------------------------------------------+
void ManageOrder(double smaCurrent, double macdCurrent, bool smaCrossedAboveBBMiddle,
                 bool smaCrossedBelowBBMiddle, double sma200Current) {
   for(int i = 0; i < OrdersTotal(); i++) {
      if(OrderSelect(i, SELECT_BY_POS) && OrderSymbol() == Symbol()) {
         // Apply trailing stop logic
         ApplyTrailingStop(OrderType(), OrderOpenPrice());

         // Check if it is necessary to close and reverse the order
         if(OrderType() == OP_BUY && (smaCurrent < sma200Current || (smaCrossedBelowBBMiddle && macdCurrent < 0))) {
            if(OrderClose(OrderTicket(), OrderLots(), Bid, 3, clrNONE)) {
               if (smaCurrent < sma200Current) {
                  EnterMarketOrder(OP_SELL);
               }
            }
         } else if(OrderType() == OP_SELL && (smaCurrent > sma200Current || (smaCrossedAboveBBMiddle && macdCurrent > 0))) {
            if(OrderClose(OrderTicket(), OrderLots(), Ask, 3, clrNONE)) {
               if (smaCurrent > sma200Current) {
                  EnterMarketOrder(OP_BUY);
               }
            }
         }

         break; // Only one trade at a time
      }
   }
}

//+------------------------------------------------------------------+
//| Apply the trailing stop to the selected open order               |
//+------------------------------------------------------------------+
void ApplyTrailingStop(int orderType, double orderOpenPrice) {
    double trailStopLevel = 0.0;

    if (orderType == OP_BUY) {
        trailStopLevel = Bid - TrailingStopPips * Point;
        if (trailStopLevel > OrderStopLoss() && trailStopLevel < orderOpenPrice) {
            OrderModify(OrderTicket(), orderOpenPrice, trailStopLevel, OrderTakeProfit(), 0, clrNONE);
        }
    } else if (orderType == OP_SELL) {
        trailStopLevel = Ask + TrailingStopPips * Point;
        if (trailStopLevel < OrderStopLoss() && trailStopLevel > orderOpenPrice) {
            OrderModify(OrderTicket(), orderOpenPrice, trailStopLevel, OrderTakeProfit(), 0, clrNONE);
        }
    }
}

